export interface Book {
  id: string;
  title: string;
  subtitle?: string;
  authorId: string;
  authorName: string;
  publisher: string;
  publishDate: string;
  isbn: string;
  language: string;
  genre: string;
  price: number;
  originalPrice?: number;
  summary: string;
  coverUrl: string;
  galleryUrls?: string[];
  purchaseLinks: {
    amazon?: string;
    appleBooks?: string;
    barnesNoble?: string;
    kobo?: string;
    publisherSite?: string;
  };
  keywords: string[];
  targetAudience?: string;
  sampleChapter?: string;
  trailerUrl?: string;
  rating: number;
  views: number;
  purchaseClicks: number;
  isFeatured?: boolean;
  isTopBook?: boolean;
  isNewAdded?: boolean;
  isTrending?: boolean;
  status: 'approved' | 'pending' | 'rejected';
  rejectionReason?: string;
}

export interface Category {
  id: string;
  name: string;
  icon: string; // Emoji or SVG name
  count: number;
}

export interface Author {
  id: string;
  name: string;
  email: string;
  bio: string;
  profileImage: string;
  isVerified: boolean;
  verificationStatus: 'verified' | 'pending' | 'unverified' | 'rejected';
  joinDate: string;
}

export interface Review {
  id: string;
  bookId: string;
  userName: string;
  rating: number;
  comment: string;
  date: string;
}

export interface Subscription {
  id: string;
  name: string;
  price: number;
  duration: string;
  features: string[];
}

export interface Transaction {
  id: string;
  authorId: string;
  authorName: string;
  planName: string;
  amount: number;
  paymentMethod: 'Stripe' | 'Razorpay' | 'PayPal';
  transactionId: string;
  date: string;
  status: 'success' | 'failed' | 'pending';
  invoiceNumber: string;
}

export interface Notification {
  id: string;
  userId: string; // author ID or 'admin'
  title: string;
  message: string;
  date: string;
  read: boolean;
}

export interface Newsletter {
  id: string;
  subject: string;
  content: string;
  dateSent: string;
  subscribersCount: number;
  clicksCount: number;
  status: 'sent' | 'scheduled' | 'draft';
}

